('34', '1', '0', 0x62617374696f646f6e, '0', '6', 0x39, '0', '0', 0x32, '0', '0', '0', '60', 0x3532, 0x313638, '47', '138', '30', '199', 0x3830, '231', '128', '45', '32', '0', '62', '', '', '', '', '0', '0', 'Sturdy|100|Soundproof|10', '', 'When they lined up side by side, no foe could break through. They shielded their young in that way.', '', '', '', '', ''),
