('36', '1', '0', 0x62656172746963, '0', '15', '0', '0', 0x32, '0', '0', '0', '0', '95', 0x313130, 0x3830, '70', '80', '50', '170', 0x313430, '13', '128', '60', '128', '2', '42', '', '', '', '', '0', '0', 'Snow Cloak|100|Swift Swim|10', '', 'They love the cold seas of the north. They create pathways across the ocean waters by freezing their own breath.', '', '', '', '', ''),
