('38', '1', '0', 0x6265656472696c6c, '0', '7', 0x34, '0', 0x32, '0', '0', 0x31, '0', '65', 0x3830, 0x3430, '45', '80', '75', '159', 0x3136, '83', '128', '45', '128', '2', '22', '', '', '', '', '0', '0', 'Swarm|100|Sniper|10', '', 'Its best attack involves flying around at high speed, striking with poison needles, then flying off.', '', '', '', '', ''),
('39', '1', '0', 0x626568656579656d, '0', '14', '0', '0', '0', '0', '2', '0', '0', '75', 0x3735, 0x3735, '125', '95', '40', '170', 0x3138, '17', '128', '90', '128', '2', '42', '', '', '', '', '0', '0', 'Telepathy|100|Synchronize|50|Analytic|10', '', 'Apparently, it communicates by flashing its three fingers, but those patterns haven\'t been decoded.', '', '', '', '', ''),
