('42', '1', '0', 0x62656c6c7370726f7574, '0', '12', 0x34, '0', 0x31, '0', '0', '0', '0', '50', 0x3735, 0x3335, '70', '30', '40', '84', 0x32, '230', '128', '255', '128', '3', '42', 'if ($this->Level() >=21) return \'Weepinbell\';', '', '', '', '0', '0', 'Chlorophyll|100|Gluttony|10', '', 'It prefers hot and humid environments. It is quick at capturing prey with its vines.', '', '', '', '', ''),
('43', '1', '0', 0x6269626172656c, '0', '1', 0x3131, '0', 0x32, '0', '0', '0', '0', '79', 0x3835, 0x3630, '55', '60', '71', '116', 0x3136, '239', '128', '127', '128', '2', '32', '', '', '', '', '0', '0', 'Simple|100|Unaware|50|Moody|10', '', 'A river dammed by Bibarel will never overflow its banks, which is appreciated by people nearby.', '', '', '', '', ''),
