('623', '1', '0', 0x77656570696e62656c6c, '0', '12', 0x34, '0', 0x32, '0', '0', '0', '0', '65', 0x3930, 0x3530, '85', '45', '55', '151', 0x34, '180', '128', '120', '128', '3', '42', 'if (strcmp($item,\'Leaf Stone\')==0) return \'Victreebel\';', '', '', '', '0', '0', 'Chlorophyll|100|Gluttony|10', '', 'A Pokémon that appears to be a plant. It captures unwary prey by dousing them with a toxic powder.', '', '', '', '', ''),
('624', '1', '0', 0x7765657a696e67, '0', '4', '0', '0', '0', 0x32, '0', '0', '0', '65', 0x3930, 0x313230, '85', '70', '60', '173', 0x36, '225', '128', '60', '128', '2', '42', '', '', '', '', '0', '0', 'Levitate|100', '', 'Inhaling toxic fumes from trash and mixing them inside its body lets it spread an even fouler stench.', '', '', '', '', ''),
('625', '1', '0', 0x7768696d7369636f7474, '0', '12', '0', '0', '0', '0', '0', '0', '2', '60', 0x3637, 0x3835, '77', '75', '116', '168', 0x34, '14', '128', '75', '128', '2', '42', '', '', '', '', '0', '0', 'Prankster|100|Infiltrator|50|Chlorophyll|10', '', 'They appear along with whirlwinds. They pull pranks, such as moving furniture and leaving balls of cotton in homes.', '', '', '', '', ''),
('626', '1', '0', 0x776869726c6970656465, '0', '7', 0x34, '0', '0', 0x32, '0', '0', '0', '40', 0x3535, 0x3939, '40', '79', '47', '126', 0x3332, '8', '128', '120', '128', '3', '32', 'if ($this->Level() >=30) return \'Scolipede\';', '', '', '', '0', '0', 'Poison Point|100|Swarm|50|Quick Feet|10', '', 'Storing energy for evolution, it sits. But, when predators approach, it moves to stab them with poison spikes.', '', '', '', '', ''),
('627', '1', '0', 0x7768697363617368, '0', '11', 0x35, 0x32, '0', '0', '0', '0', '0', '110', 0x3738, 0x3733, '76', '71', '60', '158', 0x3132, '255', '128', '75', '128', '2', '42', '', '', '', '', '0', '0', 'Oblivious|100|Anticipation|50|Hydration|10', '', 'It is extremely protective of its territory. If any foe approaches, it attacks using vicious tremors.', '', '', '', '', ''),
('628', '1', '0', 0x776869736d7572, '0', '1', '0', 0x31, '0', '0', '0', '0', '0', '64', 0x3531, 0x3233, '51', '23', '28', '68', 0x38, '172', '128', '190', '128', '3', '42', 'if ($this->Level() >=20) return \'Loudred\';', '', '', '', '0', '0', 'Soundproof|100|Rattled|10', '', 'Usually, its cries are like quiet murmurs. If frightened, it shrieks at the same volume as a jet plane.', '', '', '', '', ''),
('629', '1', '0', 0x776967676c7974756666, '0', '1', '0', 0x33, '0', '0', '0', '0', '0', '140', 0x3730, 0x3435, '75', '50', '45', '109', 0x36, '240', '128', '50', '191', '1', '42', '', '', '', '', '0', '0', 'Cute Charm|100|Frisk|10', '', 'Its fine fur feels so pleasant, those who accidentally touch it cannot take their hands away.', '', '', '', '', ''),
('630', '1', '0', 0x77696e67756c6c, '0', '11', 0x33, '0', '0', '0', '0', '0', '1', '40', 0x3330, 0x3330, '55', '30', '85', '64', 0x36, '201', '128', '190', '128', '2', '42', 'if ($this->Level() >=25) return \'Pelipper\';', '', '', '', '0', '0', 'Keen Eye|100|Rain Dish|10', '', 'It makes its nest on sheer cliffs. Riding the sea breeze, it glides up into the expansive skies.', '', '', '', '', ''),
('631', '1', '0', 0x776f62627566666574, '0', '14', '0', 0x32, '0', '0', '0', '0', '0', '190', 0x3333, 0x3538, '33', '58', '33', '177', 0x3136, '255', '128', '45', '128', '2', '42', '', '', '', '', '0', '0', 'Shadow Tag|100|Telepathy|10', '', 'It desperately tries to keep its black tail hidden. It is said to be proof the tail hides a secret.', '', '', '', '', ''),
('632', '1', '0', 0x776f6f626174, '0', '14', 0x33, '0', '0', '0', '0', '0', '1', '55', 0x3435, 0x3433, '55', '43', '72', '63', 0x32, '9', '128', '190', '128', '2', '32', 'if ($this->Emotion(\'Friendship\') > 128) return \'Swoobat\';', '', '', '', '0', '0', 'Unaware|100|Klutz|50|Simple|10', '', 'The heart-shaped mark left on a body after a Woobat has been attached to it is said to bring good fortune.', '', '', '', '', ''),
('633', '1', '0', 0x776f6f706572, '0', '11', 0x35, 0x31, '0', '0', '0', '0', '0', '55', 0x3435, 0x3435, '25', '25', '15', '52', 0x34, '194', '128', '255', '128', '2', '42', 'if ($this->Level() >=20) return \'Quagsire\';', '', '', '', '0', '0', 'Damp|100|Water Absorb|50|Unaware|10', '', 'When walking on land, it covers its body with a poisonous film that keeps its skin from dehydrating.', '', '', '', '', ''),
('634', '1', '0', 0x776f726d6164616d, '0', '7', 0x3132, '0', '0', '0', '0', 0x32, '0', '60', 0x3539, 0x3835, '79', '105', '36', '159', 0x34, '3', '128', '45', '254', '2', '32', '', '', '', '', '0', '0', 'Anticipation|100|Overcoat|10', '', 'When evolving, its body takes in surrounding materials. As a result, there are many body variations.', '', '', '', '', ''),
('635', '1', '0', 0x7775726d706c65, '0', '7', '0', 0x31, '0', '0', '0', '0', '0', '45', 0x3435, 0x3335, '20', '30', '20', '54', 0x32, '191', '128', '255', '128', '2', '32', '', '', '', '', '0', '0', 'Shield Dust|100|Run Away|10', '', 'Often targeted by bird Pokémon, it desperately resists by releasing poison from its tail spikes.', '', '', '', '', ''),
('636', '1', '0', 0x77796e617574, '0', '14', '0', 0x31, '0', '0', '0', '0', '0', '95', 0x3233, 0x3438, '23', '48', '23', '44', 0x38, '252', '128', '125', '128', '2', '42', 'if ($this->Level() >=15) return \'Wobbuffet\';', '', '', '', '0', '0', 'Shadow Tag|100|Telepathy|10', '', 'It grows strong by pushing up against others en masse. It loves eating sweet fruit.', '', '', '', '', ''),
('637', '1', '0', 0x78617475, '0', '14', 0x33, '0', '0', '0', '1', '0', '1', '65', 0x3735, 0x3730, '95', '70', '95', '171', 0x38, '181', '128', '75', '128', '2', '42', '', '', '', '', '0', '0', 'Synchronize|100|Early Bird|50|Magic Bounce|10', '', 'This odd Pokémon can see both the past and the future. It eyes the sun\'s movement all day.', '', '', '', '', ''),
('638', '1', '0', 0x79616d61736b, '0', '8', '0', '0', '0', 0x31, '0', '0', '0', '38', 0x3330, 0x3835, '55', '65', '30', '61', '0', '14', '128', '190', '128', '2', '52', 'if ($this->Level() >=34) return \'Cofagrigus\';', '', '', '', '0', '0', 'Mummy|100', '', 'These Pokémon arose from the spirits of people interred in graves. Each retains memories of its former life.', '', '', '', '', ''),
('639', '1', '0', 0x79616e6d61, '0', '7', 0x33, '0', '0', '0', '0', '0', '1', '65', 0x3635, 0x3435, '75', '45', '95', '147', 0x3230, '165', '128', '75', '128', '2', '42', '', '', '', '', '0', '0', 'Speed Boost|100|Compoundeyes|50|Frisk|10', '', 'By flapping its wings at high speed, it can fly freely through the air. Even sudden stops are no problem.', '', '', '', '', ''),
('640', '1', '0', 0x79616e6d656761, '0', '7', 0x33, '0', 0x32, '0', '0', '0', '0', '86', 0x3736, 0x3836, '116', '56', '95', '198', 0x3238, '174', '128', '30', '128', '2', '42', '', '', '', '', '0', '0', 'Speed Boost|100|Tinted Lens|50|Frisk|10', '', 'It prefers to battle by biting apart foes\' heads instantly while flying by at high speed.', '', '', '', '', ''),
