('642', '1', '0', 0x7a6170646f73, '0', '13', 0x33, '0', '0', '0', '3', '0', '0', '90', 0x3930, 0x3835, '125', '90', '100', '216', 0x3238, '140', '64', '3', '255', '4', '162', '', '', '', '', '0', '0', 'Pressure|100|Lightningrod|10', '', 'A legendary Pokémon that is said to live in thunderclouds. It freely controls lightning bolts.', '', '', '', '', ''),
('643', '1', '0', 0x7a6562737472696b61, '0', '13', '0', '0', '0', '0', '0', '0', '2', '75', 0x313030, 0x3633, '80', '63', '116', '174', 0x3432, '23', '128', '75', '128', '2', '42', '', '', '', '', '0', '0', 'Lightningrod|100|Motor Drive|50|Sap Sipper|10', '', 'When this ill-tempered Pokémon runs wild, it shoots lightning from its mane in all directions.', '', '', '', '', ''),
