INSERT INTO `move` (`id`, `uid`, `approved`, `name`, `type`, `power`, `pp`, `speed`, `accuracy`, `target`, `damage_type`, `script_select`, `script_execute`, `description`) VALUES 
('1', '0', '0', 0x706f756e64, '1', '40', 0x3335, '0', 0x313030, 0x3130, '2', '', '', 'The target is physically pounded with a long tail or a foreleg, etc.'),
('2', '0', '0', 0x6b61726174652063686f70, '2', '50', 0x3235, '0', 0x313030, 0x3130, '2', '', '', 'The target is attacked with a sharp chop. Critical hits land more easily.'),
('3', '0', '0', 0x646f75626c65736c6170, '1', '15', 0x3130, '0', 0x3835, 0x3130, '2', '', '', 'The target is slapped repeatedly, back and forth, two to five times in a row.'),
('4', '0', '0', 0x636f6d65742070756e6368, '1', '18', 0x3135, '0', 0x3835, 0x3130, '2', '', '', 'The target is hit with a flurry of punches that strike two to five times in a row.'),
('5', '0', '0', 0x6d6567612070756e6368, '1', '80', 0x3230, '0', 0x3835, 0x3130, '2', '', '', 'The target is slugged by a punch thrown with muscle-packed power.'),
('6', '0', '0', 0x70617920646179, '1', '40', 0x3230, '0', 0x313030, 0x3130, '2', '', '', 'Numerous coins are hurled at the target to inflict damage. Money is earned after the battle.'),
('7', '0', '0', 0x666972652070756e6368, '10', '75', 0x3135, '0', 0x313030, 0x3130, '2', '', '', 'The target is punched with a fiery fist. It may also leave the target with a burn.'),
('8', '0', '0', 0x6963652070756e6368, '15', '75', 0x3135, '0', 0x313030, 0x3130, '2', '', '', 'The target is punched with an icy fist. It may also leave the target frozen.'),
('9', '0', '0', 0x7468756e64657270756e6368, '13', '75', 0x3135, '0', 0x313030, 0x3130, '2', '', '', 'The target is punched with an electrified fist. It may also leave the target with paralysis.'),
('10', '0', '0', 0x73637261746368, '1', '40', 0x3335, '0', 0x313030, 0x3130, '2', '', '', 'Hard, pointed, and sharp claws rake the target to inflict damage.'),
('11', '0', '0', 0x7669636567726970, '1', '55', 0x3330, '0', 0x313030, 0x3130, '2', '', '', 'The target is gripped and squeezed from both sides to inflict damage.'),
('12', '0', '0', 0x6775696c6c6f74696e65, '1', '1', 0x35, '0', 0x3330, 0x3130, '2', '', '', 'A vicious, tearing attack with big pincers. The target will faint instantly if this attack hits.'),
('13', '0', '0', 0x72617a6f722077696e64, '1', '80', 0x3130, '0', 0x313030, 0x3131, '3', '', '', 'A two-turn attack. Blades of wind hit opposing Pokémon on the second turn. Critical hits land more easily.'),
('14', '0', '0', 0x73776f7264732064616e6365, '1', '0', 0x3330, '0', '0', 0x37, '1', '', '', 'A frenetic dance to uplift the fighting spirit. It sharply raises the user\'s Attack stat.'),
('15', '0', '0', 0x637574, '1', '50', 0x3330, '0', 0x3935, 0x3130, '2', '', '', 'The target is cut with a scythe or a claw. It can also be used to cut down thin trees.'),
('16', '0', '0', 0x67757374, '3', '40', 0x3335, '0', 0x313030, 0x3130, '3', '', '', 'A gust of wind is whipped up by wings and launched at the target to inflict damage.'),
('17', '0', '0', 0x77696e672061747461636b, '3', '60', 0x3335, '0', 0x313030, 0x3130, '2', '', '', 'The target is struck with large, imposing wings spread wide to inflict damage.'),
('18', '0', '0', 0x776869726c77696e64, '1', '0', 0x3230, '0', 0x313030, 0x3130, '1', '', '', 'The target is blown away and switched. In the wild, a battle against a single Pokémon ends.'),
('19', '0', '0', 0x666c79, '3', '90', 0x3135, '0', 0x3935, 0x3130, '2', '', '', 'The user soars, then strikes its target on the second turn. It can also be used for flying to any familiar town.'),
('20', '0', '0', 0x62696e64, '1', '15', 0x3230, '0', 0x3835, 0x3130, '2', '', '', 'Things such as long bodies or tentacles are used to bind and squeeze the target for four to five turns.'),
('21', '0', '0', 0x736c616d, '1', '80', 0x3230, '0', 0x3735, 0x3130, '2', '', '', 'The target is slammed with a long tail, vines, etc., to inflict damage.'),
('22', '0', '0', 0x76696e652077686970, '12', '35', 0x3135, '0', 0x313030, 0x3130, '2', '', '', 'The target is struck with slender, whiplike vines to inflict damage.'),
('23', '0', '0', 0x73746f6d70, '1', '65', 0x3230, '0', 0x313030, 0x3130, '2', '', '', 'The target is stomped with a big foot. It may also make the target flinch.'),
('24', '0', '0', 0x646f75626c65206b69636b, '2', '30', 0x3330, '0', 0x313030, 0x3130, '2', '', '', 'The target is quickly kicked twice in succession using both feet.'),
('25', '0', '0', 0x6d656761206b69636b, '1', '120', 0x35, '0', 0x3735, 0x3130, '2', '', '', 'The target is attacked by a kick launched with muscle-packed power.'),
('26', '0', '0', 0x6a756d70206b69636b, '2', '100', 0x3130, '0', 0x3935, 0x3130, '2', '', '', 'The user jumps up high, then strikes with a kick. If the kick misses, the user hurts itself.'),
('27', '0', '0', 0x726f6c6c696e67206b69636b, '2', '60', 0x3135, '0', 0x3835, 0x3130, '2', '', '', 'The user lashes out with a quick, spinning kick. It may also make the target flinch.'),
('28', '0', '0', 0x73616e642061747461636b, '5', '0', 0x3135, '0', 0x313030, 0x3130, '1', '', '', 'Sand is hurled in the target\'s face, reducing its accuracy.'),
